@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject IComponentInteropService Interop

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium text-foreground mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div id="@EffectiveId" class="@CssClass" role="radiogroup" aria-label="@L["Rating.Rate"]" aria-orientation="horizontal" aria-describedby="@FormFieldDescribedBy" @onkeydown="HandleKeyDown" @onpointerup="HandlePointerUp" @onpointerleave="HandlePointerLeaveContainer" @onpointercancel="HandlePointerUp" @attributes="EffectiveAttributes">
    @for (int i = 1; i <= Max; i++)
    {
        var starIndex = i;
        var isFull = Value >= starIndex;
        var isHalf = AllowHalf && !isFull && Value >= starIndex - 0.5;

        @if (IconContent is not null)
        {
            <button type="button"
                    role="radio"
                    aria-checked="@(IsStarChecked(starIndex).ToString().ToLowerInvariant())"
                    class="@GetStarClasses(isFull || isHalf) @SizeClasses @StarInteractClasses"
                    tabindex="@GetStarTabIndex(starIndex)"
                    disabled="@ReadOnly"
                    aria-label="@(string.Format(L["Rating.RateOf"], starIndex, Max))"
                    @onclick="() => HandleClick(starIndex)"
                    @onpointerdown="(e) => HandlePointerDown(starIndex, e)"
                    @onpointerenter="() => HandlePointerEnter(starIndex)"
                    @onmouseover="() => HandleHover(starIndex)"
                    @onmouseout="HandleMouseLeave">
                @IconContent
            </button>
        }
        else
        {
            <button type="button"
                    role="radio"
                    aria-checked="@(IsStarChecked(starIndex).ToString().ToLowerInvariant())"
                    class="@SizeClasses @StarInteractClasses relative"
                    tabindex="@GetStarTabIndex(starIndex)"
                    disabled="@ReadOnly"
                    aria-label="@(string.Format(L["Rating.RateOf"], starIndex, Max))"
                    @onclick="() => HandleClick(starIndex)"
                    @onpointerdown="(e) => HandlePointerDown(starIndex, e)"
                    @onpointerenter="() => HandlePointerEnter(starIndex)"
                    @onmouseover="() => HandleHover(starIndex)"
                    @onmouseout="HandleMouseLeave">
                @* Always render the stars inside the same inline-grid wrapper — using the wrapper for half-stars
                   only put them on a different baseline than the plain full/empty star glyphs and made
                   half-stars sit slightly lower in the row. Now every star shares the same line-box geometry. *@
                <span class="inline-grid align-middle leading-none [&_svg]:block" style="grid-template-areas: 'stack';">
                    <span style="grid-area: stack;">
                        <SvgGlyph Svg="@(LumeoIcons.Star)" class="text-muted-foreground/30 fill-muted-foreground/10" />
                    </span>
                    @if (isFull || (_hoverValue > 0 && starIndex <= _hoverValue))
                    {
                        <span style="grid-area: stack;">
                            <SvgGlyph Svg="@(LumeoIcons.Star)" class="text-[var(--color-rating)] fill-[var(--color-rating)]" />
                        </span>
                    }
                    else if (isHalf)
                    {
                        <span style="grid-area: stack; clip-path: inset(0 50% 0 0);">
                            <SvgGlyph Svg="@(LumeoIcons.Star)" class="text-[var(--color-rating)] fill-[var(--color-rating)]" />
                        </span>
                    }
                </span>
            </button>
        }
    }
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive mt-1.5">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground mt-1.5">@HelperText</p>
    }
}
</div>

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    // aria-describedby on the radiogroup announces the FormField help/error to a screen
    // reader.
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Inside a FormField, adopt its ControlId as the radiogroup's id so the field's
    // <Label For> actually associates with the group (Base UI Field parity, mirroring
    // Select/RadioGroup). Standalone, keep our own generated id. Every internal id use
    // — the rendered id attribute AND the preventDefault-keys interop register/unregister
    // — flows through this so the rendered id and the JS-targeted element stay consistent.
    private string EffectiveId =>
        !string.IsNullOrEmpty(FormField?.ControlId) ? FormField!.ControlId : _id;

    /// <summary>The current rating, from 0 up to <see cref="Max"/>. Two-way bindable via <see cref="ValueChanged"/>. Fractional <c>.5</c> values are only meaningful when <see cref="AllowHalf"/> is set.</summary>
    [Parameter] public double Value { get; set; }
    /// <summary>Raised whenever the rating changes, via click, drag, or arrow-key navigation.</summary>
    [Parameter] public EventCallback<double> ValueChanged { get; set; }
    /// <summary>Number of stars rendered. Default 5.</summary>
    [Parameter] public int Max { get; set; } = 5;
    /// <summary>Allows selecting half-star values (clicking an already-selected star toggles it down by 0.5).</summary>
    [Parameter] public bool AllowHalf { get; set; }
    /// <summary>Disables all interaction (click, drag, keyboard), rendering the stars as a static display.</summary>
    [Parameter] public bool ReadOnly { get; set; }

    /// <summary>Icon slot. Named <c>IconContent</c> to avoid shadowing the <c>&lt;Icon&gt;</c> component.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    /// <summary>Star size. Default <see cref="Lumeo.Size.Md"/>.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    /// <summary>Marks the field as required, appending a destructive-colored asterisk to the label (outside a <c>FormField</c>). Purely visual — the widget does not enforce a non-zero selection.</summary>
    [Parameter] public bool Required { get; set; }
    /// <summary>Forces the invalid/error visual state (destructive error text), independent of the ambient <c>FormField</c>'s validation state.</summary>
    [Parameter] public bool Invalid { get; set; }
    /// <summary>Error message shown below the stars (outside a <c>FormField</c>) when <see cref="Invalid"/> is set. Takes precedence over <see cref="HelperText"/>.</summary>
    [Parameter] public string? ErrorText { get; set; }
    /// <summary>Helper text shown below the stars (outside a <c>FormField</c>) when there is no error to display.</summary>
    [Parameter] public string? HelperText { get; set; }
    /// <summary>Label text rendered above the stars (outside a <c>FormField</c>, which supplies its own label).</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>Field name for form-field integration. Not currently rendered onto the radiogroup markup.</summary>
    [Parameter] public string? Name { get; set; }
    /// <summary>Additional CSS classes merged onto the star row (the <c>role="radiogroup"</c> element).</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the star row (the <c>role="radiogroup"</c> element).</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Inside a FormField the generated id must own this element so the FormField <Label For> (and any
    // interop keyed off the id) stays valid; a consumer-splatted id in AdditionalAttributes renders after
    // the explicit id= and would override it. Strip it here when InsideFormField; outside, pass through.
    private Dictionary<string, object>? EffectiveAttributes =>
        InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    private readonly string _id = LumeoIds.New("rating");

    private int _hoverValue;

    // Touch/pointer drag state. Lets users tap-and-drag across stars (iOS-style)
    // to scrub the value continuously. _suppressNextClick avoids double-handling
    // when the synthetic click follows a pointerdown that already set the value.
    private bool _isDragging;
    private bool _suppressNextClick;
    private bool _dragMovedAcrossStars;

    // Roving tabindex: only the selected star (or star 1 when nothing selected) is
    // in the tab sequence. Arrow-key navigation on the radiogroup shifts both focus
    // and value, so there is never more than one tabstop inside the widget.
    //
    // Clamp the active index to the rendered range [1, Max]: if Max shrinks below the
    // current Value (e.g. Value=5 then Max=3), the unclamped active index (5) names a
    // star that is no longer rendered, so NO star would carry tabindex="0" and the
    // widget would silently drop out of the tab order. Clamping keeps exactly one
    // tabstop — the last rendered star — so the widget stays keyboard-reachable.
    private string GetStarTabIndex(int starIndex)
    {
        var activeIndex = Value > 0 ? Math.Min((int)Math.Ceiling(Value), Max) : 1;
        return starIndex == activeIndex ? "0" : "-1";
    }

    // ARIA single-selection contract: a role="radiogroup" must report aria-checked="true"
    // on AT MOST ONE role="radio". The visual fill ("all stars up to Value are coloured")
    // is driven independently by classes / isFull, so checked must mark only the single
    // star that represents the current Value — not every filled star. We round Value up
    // (a half-star at N-0.5 selects star N) and clamp to Max so the checked star is the
    // same one the roving tabindex makes tabbable. Value==0 (no selection) reports no
    // checked radio, which is valid for an as-yet-unselected radio group.
    private bool IsStarChecked(int starIndex) =>
        Value > 0 && starIndex == Math.Min((int)Math.Ceiling(Value), Max);

    private string CssClass => Cx.Merge("inline-flex items-center gap-0.5", Class);

    private string SizeClasses => Size switch
    {
        Lumeo.Size.Sm => "[&_svg]:h-4 [&_svg]:w-4",
        Lumeo.Size.Lg => "[&_svg]:h-8 [&_svg]:w-8",
        _ => "[&_svg]:h-5 [&_svg]:w-5"
    };

    private string GetStarClasses(bool isActive) => isActive
        ? "text-[var(--color-rating)]"
        : "text-muted-foreground/30";

    private string StarInteractClasses => ReadOnly
        ? "cursor-default"
        : "cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-sm";

    private async Task HandleClick(int index)
    {
        if (ReadOnly) return;

        // When a pointerdown already committed the value (touch/pen, or any drag),
        // skip the synthetic click that follows to avoid double-handling. For
        // AllowHalf this is critical: the click would otherwise toggle to N-0.5.
        if (_suppressNextClick)
        {
            _suppressNextClick = false;
            return;
        }

        var newValue = (double)index;
        if (AllowHalf && Value == index)
        {
            newValue = index - 0.5;
        }

        Value = newValue;
        await ValueChanged.InvokeAsync(Value);
    }

    private async Task HandlePointerDown(int index, PointerEventArgs e)
    {
        if (ReadOnly) return;

        // Only handle touch/pen here. For mouse we let @onclick continue to drive
        // value changes so the existing AllowHalf toggle behaviour (click again
        // for half-star) keeps working on desktop. Without this guard,
        // pointerdown commits Value=N then the synthetic click sees Value==N
        // and toggles to N-0.5 — double-fire with wrong final value.
        if (e.PointerType == "mouse") return;

        _isDragging = true;
        _dragMovedAcrossStars = false;

        // Commit initial value on touch so the first contact shows feedback
        // immediately, matching native iOS scrubber behaviour.
        if (Value != index)
        {
            Value = index;
            await ValueChanged.InvokeAsync(Value);
        }
    }

    private async Task HandlePointerEnter(int index)
    {
        if (ReadOnly || !_isDragging) return;

        // Pointer crossed into a different star while dragging — scrub value.
        _dragMovedAcrossStars = true;
        if (Value != index)
        {
            Value = index;
            await ValueChanged.InvokeAsync(Value);
        }
    }

    private void HandlePointerUp()
    {
        if (!_isDragging) return;

        // If the user actually dragged, suppress the trailing click so we don't
        // re-toggle the value. A pure tap (no movement) still falls through to
        // HandleClick which honours the AllowHalf half-star toggle.
        if (_dragMovedAcrossStars)
        {
            _suppressNextClick = true;
        }

        _isDragging = false;
        _dragMovedAcrossStars = false;
    }

    private void HandlePointerLeaveContainer()
    {
        // Finger slid out of the radiogroup entirely — end the drag so a later
        // pointerup outside the widget doesn't leave us stuck in dragging state.
        if (_isDragging)
        {
            _isDragging = false;
            _dragMovedAcrossStars = false;
        }
    }

    private void HandleHover(int index)
    {
        if (!ReadOnly)
        {
            _hoverValue = index;
        }
    }

    private void HandleMouseLeave()
    {
        _hoverValue = 0;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (ReadOnly) return;

        var step = AllowHalf ? 0.5 : 1.0;
        double newValue = Value;

        switch (e.Key)
        {
            case "ArrowRight":
            case "ArrowUp":
                newValue = Math.Min(Value + step, Max);
                break;
            case "ArrowLeft":
            case "ArrowDown":
                newValue = Math.Max(Value - step, 0);
                break;
            case "Home":
                newValue = 0;
                break;
            case "End":
                newValue = Max;
                break;
            default:
                return;
        }

        if (newValue != Value)
        {
            Value = newValue;
            await ValueChanged.InvokeAsync(Value);
        }
    }

    // The arrow / Home / End keys all change the rating; without suppressing the
    // browser default they ALSO scroll the page (#189). A native key-selective
    // preventDefault is the only race-free way to cancel the current event —
    // Blazor's @onkeydown:preventDefault is applied at render time and so lags
    // one keystroke. We never register while ReadOnly (no value change to make).
    private bool _pdRegistered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (ReadOnly)
        {
            // A rating toggled to ReadOnly after mounting should release the
            // suppression so arrow keys scroll normally again.
            if (_pdRegistered)
            {
                try { await Interop.UnregisterPreventDefaultKeys(EffectiveId); }
                catch (JSDisconnectedException) { }
                catch (ObjectDisposedException) { }
                catch (InvalidOperationException) { }
                _pdRegistered = false;
            }
            return;
        }

        if (_pdRegistered) return;
        try
        {
            await Interop.RegisterPreventDefaultKeys(
                EffectiveId,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End" }
                    .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try { await Interop.UnregisterPreventDefaultKeys(EffectiveId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
